export default function Ext() {
    return (
        <div className="EXT-area ">
            <div className="product-card">
                <img src="product-image.jpg" alt="Product Image" />
                    <h3 className="product-title">Product Name</h3>
                    <p className="product-price">$99.99</p>
            </div>

        </div>
    )

}
